-- issuersテーブルの作成
CREATE TABLE IF NOT EXISTS `issuers` (
  `id` int AUTO_INCREMENT PRIMARY KEY,
  `name` varchar(255) NOT NULL,
  `code` varchar(50) UNIQUE,
  `category` varchar(100),
  `sortOrder` int DEFAULT 0 NOT NULL,
  `isActive` boolean DEFAULT true NOT NULL,
  `createdAt` timestamp DEFAULT CURRENT_TIMESTAMP NOT NULL,
  `updatedAt` timestamp DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP NOT NULL,
  INDEX `sortOrder_idx` (`sortOrder`),
  INDEX `isActive_idx` (`isActive`)
);

-- biddingsテーブルにカラムを追加
ALTER TABLE `biddings` ADD COLUMN `tenderCanonicalId` varchar(255) NOT NULL DEFAULT '';
ALTER TABLE `biddings` ADD COLUMN `lastUpdatedAtSource` timestamp NULL;
ALTER TABLE `biddings` ADD COLUMN `firstSeenAt` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP;
ALTER TABLE `biddings` ADD COLUMN `lastSeenAt` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP;

-- インデックスを追加
ALTER TABLE `biddings` ADD INDEX `tenderCanonicalId_idx` (`tenderCanonicalId`);
ALTER TABLE `biddings` ADD INDEX `firstSeenAt_idx` (`firstSeenAt`);

-- notificationSubscriptionsテーブルにカラムを追加
ALTER TABLE `notificationSubscriptions` ADD COLUMN `issuerIds` text NULL;
ALTER TABLE `notificationSubscriptions` ADD COLUMN `projectType` varchar(50) NULL;
ALTER TABLE `notificationSubscriptions` ADD COLUMN `isFirstNotificationSent` boolean DEFAULT false NOT NULL;

-- notificationLogsテーブルにカラムを追加
ALTER TABLE `notificationLogs` ADD COLUMN `tenderCanonicalId` varchar(255) NOT NULL DEFAULT '';
ALTER TABLE `notificationLogs` ADD COLUMN `notificationType` enum('NEW', 'UPDATE') NOT NULL DEFAULT 'NEW';
ALTER TABLE `notificationLogs` ADD COLUMN `sentAt` timestamp DEFAULT CURRENT_TIMESTAMP NOT NULL;
ALTER TABLE `notificationLogs` ADD COLUMN `messageContent` text NULL;

